// =============================================
// FILTRO E LIMPEZA DE MENSAGENS (Evolution API v2)
// Extrai dados relevantes e ignora lixo
// =============================================
const body = $json.body;

// 1. Validação básica
if (!body || !body.data || !body.data.key) {
  return []; // Não é mensagem válida
}

const data = body.data;

// 2. Ignorar grupos e mensagens que EU mandei
if (data.key.remoteJid.includes('@g.us') || data.key.fromMe) {
  return [];
}

// 3. Extrair texto (suporta vários formatos da v2)
const messageText = data.message?.conversation ||
                    data.message?.extendedTextMessage?.text ||
                    data.message?.buttonsResponseMessage?.selectedButtonId || '';

// Se não tem texto (imagem, áudio, etc), ignorar por enquanto
if (!messageText.trim()) {
  return [];
}

// 4. Normalizar telefone (remover @s.whatsapp.net e código do país)
const rawPhone = data.key.remoteJid.split('@')[0];
const phone = rawPhone.replace(/\D/g, '');

// 5. pushName = nome que aparece no perfil do WhatsApp
const pushName = data.pushName || '';

return {
  phone,
  messageText: messageText.trim(),
  remoteJid: data.key.remoteJid,
  pushName,
  timestamp: new Date().toISOString()
};

// =============================================
// PREPARAR CONTEXTO PARA O AGENTE SDR
// Monta o objeto completo com dados do lead
// =============================================
const filtro = $('Filtro e Limpeza').item.json;
const supabaseResult = $json; // Array do Supabase

let lead = null;
let isNewLead = true;
let leadId = null;

// Supabase retorna array - se veio com dados, lead existe
if (Array.isArray(supabaseResult) && supabaseResult.length > 0) {
  lead = supabaseResult[0];
  isNewLead = false;
  leadId = lead.id;
} else if (supabaseResult && supabaseResult.id) {
  lead = supabaseResult;
  isNewLead = false;
  leadId = lead.id;
}

// Montar contexto rico para o agente
return {
  // Dados da mensagem
  phone: filtro.phone,
  messageText: filtro.messageText,
  remoteJid: filtro.remoteJid,
  pushName: filtro.pushName,
  timestamp: filtro.timestamp,

  // Dados do lead (do Supabase)
  isNewLead,
  leadId,
  nome_contato: lead?.nome_contato || '',
  nome_empresa: lead?.nome_empresa || '',
  segmento: lead?.segmento || 'servicos',
  status: lead?.status || 'PENDENTE',
  nome_capturado: lead?.nome_capturado || false,
  follow_up_count: lead?.follow_up_count || 0,
  total_mensagens_enviadas: lead?.total_mensagens_enviadas || 0,
  total_mensagens_recebidas: lead?.total_mensagens_recebidas || 0,
  observacao: lead?.observacao || ''
};

// =============================================
// MERGE: Unifica resultado do lead (novo ou existente)
// para alimentar o Agente SDR
// =============================================
const contexto = $('Preparar Contexto').item.json;
const leadData = $json; // Resultado do CREATE ou UPDATE

// Se Supabase retornou array, pegar primeiro
const lead = Array.isArray(leadData) ? leadData[0] : leadData;

return {
  ...contexto,
  leadId: lead?.id || contexto.leadId,
  nome_contato: lead?.nome_contato || contexto.nome_contato || contexto.pushName || '',
  nome_capturado: lead?.nome_capturado || (contexto.pushName ? true : false)
};

// Tool: Atualizar status do lead no CRM
const leadId = $('Merge Lead Data').item.json.leadId;
const novoStatus = $fromAI('status', 'O novo status do lead: INTERESSADO, AGENDADO ou RECUSADO', 'string');
const motivo = $fromAI('motivo', 'Se recusado, qual o motivo. Se não recusado, deixe vazio.', 'string');

const body = {
  status: novoStatus
};

if (novoStatus === 'RECUSADO' && motivo) {
  body.motivo_recusa = motivo;
}

const supabaseUrl = $env.get('SUPABASE_URL');
const supabaseKey = $env.get('SUPABASE_ANON_KEY');

try {
  await fetch(`${supabaseUrl}/rest/v1/leads?id=eq.${leadId}`, {
    method: 'PATCH',
    headers: {
      'apikey': supabaseKey,
      'Authorization': `Bearer ${supabaseKey}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify(body)
  });
} catch (err) {}

return {
  leadId,
  novoStatus,
  motivo,
  mensagem: `Status atualizado com sucesso no Supabase para ${novoStatus}.`
};

// Tool: Extrair nome e atualizar no Supabase
const leadId = $('Merge Lead Data').item.json.leadId;
const nome = $fromAI('nome', 'O nome que o lead informou na conversa', 'string');

const supabaseUrl = $env.get('SUPABASE_URL');
const supabaseKey = $env.get('SUPABASE_ANON_KEY');

try {
  await fetch(`${supabaseUrl}/rest/v1/leads?id=eq.${leadId}`, {
    method: 'PATCH',
    headers: {
      'apikey': supabaseKey,
      'Authorization': `Bearer ${supabaseKey}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      nome_contato: nome,
      nome_capturado: true
    })
  });
} catch (err) {}

return {
  leadId,
  nome_extraido: nome,
  mensagem: `Nome do lead atualizado com sucesso no Supabase para ${nome}.`
};

// =============================================
// HUMANIZAR TEMPO DE RESPOSTA
// Calcula delay baseado no tamanho do texto
// =============================================
const text = $json.output || '';
const textLength = text.length;

// Fórmula: (caracteres / velocidade) + tempo de "pensar" aleatório
const waitTime = Math.floor((textLength / 35) + (Math.random() * (4 - 2) + 2));

return {
  waitTimeSeconds: waitTime,
  responseText: text,
  phone: $('Merge Lead Data').item.json.phone,
  remoteJid: $('Merge Lead Data').item.json.remoteJid,
  leadId: $('Merge Lead Data').item.json.leadId
};
